          "content": "𝑅𝑎 = (𝑅𝑎 𝑣𝑎𝑙𝑢𝑒 𝑖𝑛 𝑐𝑢𝑡 𝑜𝑓𝑓 𝑙𝑒𝑛𝑔𝑡ℎ ×𝑡𝑜𝑡𝑎𝑙 𝑙𝑒𝑛𝑔𝑡ℎ) / 𝑐𝑢𝑡 𝑜𝑓𝑓 𝑙𝑒𝑛𝑔𝑡ℎ\n𝑅𝑎 = 1.463×35.57 /0.8"
